record.field:
# Recalculate all received quantities from stock.move
fill_rate_lines = env['fill.rate.line'].search([])
for line in fill_rate_lines:
    line.update_received_quantity()

# Recalculate Fill Rate for all suppliers
partners = env['res.partner'].search([('fill_rate_history_ids', '!=', False)])
for partner in partners:
    partner._compute_fill_rate()
    partner._compute_supplier_class()

# Show success message
action = {
    'type': 'ir.actions.client',
    'tag': 'display_notification',
    'params': {
        'title': 'Done!',
        'message': f'Recalculated {len(fill_rate_lines)} lines and {len(partners)} suppliers',
        'type': 'success',
        'sticky': False,
    }
}

if records:
    for partner in records:
        # Update received quantities for all supplier lines
        partner.fill_rate_history_ids.update_received_quantity()

        # Recalculate fill rate and classification
        partner._compute_fill_rate()
        partner._compute_supplier_class()

    action = {
        'type': 'ir.actions.client',
        'tag': 'display_notification',
        'params': {
            'title': 'Recalculated',
            'message': f'Fill Rate updated successfully for {len(records)} supplier(s)',
            'type': 'success',
            'sticky': False,
        }
    }

# Use the orders selected by the user
# If orders were selected, use those; otherwise search all qualifying ones
if records:
    orders = records.filtered(lambda o: o.state in ['purchase', 'done'])
else:
    orders = env['purchase.order'].search([
        ('state', 'in', ['purchase', 'done']),
        ('fill_rate_created', '=', False)
    ])

# Process orders (method handles ValidationError internally)
created_count = 0
errors = 0
processed = 0

for order in orders:
    try:
        # Only process if fill rate has not been created
        if not order.fill_rate_created:
            order.create_missing_fill_rate_lines()
            created_count += len(order.fill_rate_line_ids)
            processed += 1
    except Exception as e:
        errors += 1
        continue

# Recalculate fill rate for affected suppliers
partners = orders.mapped('partner_id')
for partner in partners:
    partner._compute_fill_rate()
    partner._compute_supplier_class()

# Show result
if errors == 0:
    message = f'Created {created_count} records for {processed} orders out of {len(orders)} selected. {len(partners)} suppliers affected.'
    msg_type = 'success'
else:
    message = f'Created {created_count} records for {processed} orders. {errors} orders had issues (see logs).'
    msg_type = 'warning'

action = {
    'type': 'ir.actions.client',
    'tag': 'display_notification',
    'params': {
        'title': 'Completed!',
        'message': message,
        'type': msg_type,
        'sticky': True,
    }
}
